INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Static Application Security Testing (SAST)$q$, $q$Scans proprietary source code for security vulnerabilities before code is deployed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Software Composition Analysis (SCA)$q$, $q$Detects vulnerable and non-compliant open-source dependencies and generates software bills of materials.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Dynamic Application Security Testing (DAST)$q$, $q$Tests running web applications for exploitable vulnerabilities from the outside in.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$API Security$q$, $q$Discovers and inventories API endpoints and flags exposure risks, including undocumented shadow APIs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Infrastructure-as-Code scanning$q$, $q$Analyzes Terraform, CloudFormation, and similar IaC templates for misconfigurations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Container security$q$, $q$Scans container images for vulnerabilities and insecure configurations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Unified Checkmarx One platform$q$, $q$Consolidates results from all scanning modules into a single risk-prioritized dashboard.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$CI/CD and SCM integrations$q$, $q$Plugs into pipelines and source control tools like GitHub, GitLab, and Azure DevOps to run scans automatically.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Consolidates SAST, SCA, DAST, and API security into one platform rather than multiple point tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Established, mature vendor with broad programming language and framework coverage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Deep CI/CD and developer-workflow integrations for shifting security left$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Backed by significant enterprise support infrastructure and a large customer base$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$No public pricing; getting an accurate cost requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Modular licensing across SAST, SCA, DAST, and other add-ons can be complex to budget for$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Primarily built for mid-size and large enterprises, less accessible for small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Can involve a steeper learning curve and tuning period to reduce false positives$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$What is Checkmarx used for?$q$, $q$Checkmarx is used for application security testing, covering static code analysis (SAST), open-source dependency scanning (SCA), dynamic testing (DAST), and API security, typically integrated into CI/CD pipelines.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$How much does Checkmarx cost?$q$, $q$Checkmarx does not publish standard pricing. Cost depends on which modules you license, number of developers, and contract length, and requires a custom quote from Checkmarx sales.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Is Checkmarx a SAST or SCA tool?$q$, $q$Checkmarx offers both. SAST and SCA were its original core products, and the Checkmarx One platform has since expanded to include DAST, API security, IaC scanning, and container security.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Who owns Checkmarx?$q$, $q$Checkmarx is privately held, owned by private equity firms Hellman & Friedman and TPG following their 2020 acquisition of the company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Does Checkmarx integrate with CI/CD pipelines?$q$, $q$Yes. Checkmarx One integrates with common CI/CD tools and source control platforms such as GitHub, GitLab, Bitbucket, and Azure DevOps to automate scans during the development process.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Enterprise DevSecOps programs$q$, $q$Large engineering organizations use Checkmarx One to run automated SAST, SCA, and DAST scans across many repositories from a single console.$q$, $q$Enterprise application security and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Regulated industry compliance$q$, $q$Companies in finance, healthcare, and government use Checkmarx to document vulnerability management and software supply-chain controls for audits.$q$, $q$Compliance and risk teams in regulated sectors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$Software supply-chain security$q$, $q$Organizations shipping software to customers use SCA and SBOM generation to track open-source risk across their products.$q$, $q$Software vendors and ISVs$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Checkmarx is an application security testing company founded in 2006 and headquartered in Ramat Gan, Israel, with significant U.S. operations centered in Atlanta. The company was acquired by private equity firms Hellman & Friedman and TPG in 2020 in a deal valued at roughly $1.15 billion, and now employs over 900 people serving enterprise customers worldwide.$q$, $q$Its flagship product, Checkmarx One, is a cloud-based application security platform that unifies static analysis, software composition analysis, dynamic testing, and API security scanning into a single console, aimed at organizations running formal DevSecOps programs across large codebases and complex software supply chains.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Checkmarx One's core modules include SAST for scanning source code before deployment, SCA for identifying vulnerable or non-compliant open-source components and generating SBOMs, DAST for testing live applications, and API Security for discovering and assessing exposed API endpoints.$q$, $q$Additional capabilities cover Infrastructure-as-Code scanning, container security, and supply-chain risk detection, along with newer tooling focused on securing AI-generated code. The platform integrates with major CI/CD systems and source control platforms so security checks can run inside existing developer workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Checkmarx does not publish standard pricing tiers. Customers choose which modules (SAST, SCA, DAST, API Security, etc.) match their needs and receive a custom quote based on factors like number of developers, scan volume, and contract term.$q$, $q$Organizations bundling multiple modules or committing to multi-year agreements typically negotiate better effective pricing than those buying a single module standalone, and larger engineering teams often unlock volume discounts.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('72d98dd7-ff9a-4d03-9e76-84a11ee4dcec', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$2,000+ pre-built integrations$q$, $q$Out-of-the-box monitoring plugins for common servers, network devices, databases, and cloud services.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Auto-discovery$q$, $q$Automatically detects hosts and services in an environment to speed up monitoring setup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Distributed monitoring$q$, $q$Scales monitoring across multiple sites and tens of thousands of hosts in higher editions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Kubernetes and cloud-native monitoring$q$, $q$Dedicated integrations for containerized and cloud workloads in the Ultimate and Cloud editions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Alerting and notification rules$q$, $q$Configurable rule-based alerting to route incidents to the right teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Full-stack observability$q$, $q$Combines infrastructure, application, and synthetic monitoring in the higher-tier editions.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Free, fully functional open-source Community edition with no artificial feature caps for small setups$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Broad integration library covering networks, servers, cloud, and applications out of the box$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Scales from small self-hosted deployments up to distributed monitoring of 100,000+ hosts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Choice between self-hosted (Pro/Ultimate) and managed SaaS (Cloud) deployment models$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Commercial pricing (services, metrics, synthetic tests) can be harder to estimate than flat per-host pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Community edition support is limited to community channels only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Nagios-based architecture may feel dated compared to newer cloud-native observability tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Cloud edition caps at 50,000 services, which may not suit the very largest environments$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Is Checkmk free?$q$, $q$Yes, the Checkmk Community edition is free and open source under the GPL, suitable for environments of roughly up to 100 hosts, though it includes community-only support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$How much does Checkmk Pro cost?$q$, $q$Checkmk Pro starts at around €190 per month when billed annually, scaling with the number of monitored services.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$What is the difference between Checkmk Pro and Ultimate?$q$, $q$Ultimate adds full-stack observability, deeper cloud-native and Kubernetes integrations, and advanced security/compliance features on top of everything in Pro, along with a higher support SLA.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Does Checkmk offer a SaaS version?$q$, $q$Yes, Checkmk Cloud is a managed SaaS edition hosted on AWS, starting at around €240 per month billed annually with a 99.5% availability guarantee.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Is Checkmk based on Nagios?$q$, $q$The Checkmk Community edition's core still uses the Nagios monitoring engine, extended with Checkmk's own agent, checks, and web interface.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Data center infrastructure monitoring$q$, $q$IT teams monitor servers, network devices, and storage across on-premises data centers using Checkmk Pro or Ultimate.$q$, $q$System administrators and IT operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Hybrid and cloud-native observability$q$, $q$DevOps teams monitor Kubernetes clusters and cloud workloads alongside traditional infrastructure using Checkmk Ultimate or Cloud.$q$, $q$DevOps and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Small business self-hosted monitoring$q$, $q$Smaller IT teams deploy the free Community edition to monitor up to roughly 100 hosts without licensing costs.$q$, $q$Small business IT administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source, GPL-licensed","Suited to ~100 hosts","2,000+ integrations","Community support only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Pro$q$, $q$From €190/month$q$, $q$Annual$q$, NULL, $q$["Self-hosted","Advanced analytics and automation","Distributed monitoring","8x5 professional support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Ultimate$q$, $q$From €275/month$q$, $q$Annual$q$, NULL, $q$["Full-stack observability","Advanced security/compliance","Cloud-native integrations","10x5 support, upgradeable to 24x5"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$Cloud$q$, $q$From €240/month$q$, $q$Annual$q$, NULL, $q$["Managed SaaS on AWS","99.5% availability guarantee","Up to 50,000 services","10x5 professional support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Checkmk traces back to 2007, when Mathias Kettner founded the company in Munich, Germany, to develop what was then called Check_MK, a monitoring tool built on the open-source Nagios core and first released under the GPL in 2009. The company was renamed tribe29 in 2019 (alongside the Checkmk product rebrand) and became Checkmk GmbH in 2023, remaining headquartered in Munich with offices in Atlanta and Minneapolis.$q$, $q$Today Checkmk is used by more than 5,000 commercial customers plus a large open-source user base to monitor hybrid IT environments spanning networks, servers, databases, cloud workloads, Kubernetes, applications, and user experience, with over 2,000 pre-built integrations available out of the box.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Checkmk automatically discovers services across an environment and provides dashboards, alerting, and notification rules for infrastructure and application monitoring. Higher editions add distributed monitoring for large multi-site environments, advanced automation, and deeper cloud-native and Kubernetes integrations.$q$, $q$The Ultimate and Cloud editions extend the platform with full-stack observability and security/compliance-oriented features, while the free Community edition retains the core monitoring engine and plugin ecosystem for smaller deployments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Checkmk Community is free and open source under the GPL, suited to environments of roughly up to 100 hosts with community-only support. Paid self-hosted editions start with Pro at around €190/month (billed annually) and Ultimate at around €275/month (billed annually), both scaling to much larger environments with professional support SLAs.$q$, $q$Checkmk Cloud, the SaaS edition hosted on AWS, starts at around €240/month (billed annually) with a 99.5% availability guarantee. Commercial pricing is based on monitored services, custom application metrics, and synthetic tests rather than a strict per-host fee.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5beb7929-33c1-44c9-ad6b-682495b32b28', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Flow payment interface$q$, $q$A customizable, prebuilt checkout UI merchants can embed on their websites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Card issuing$q$, $q$Create and manage physical and virtual payment cards through the Issuing platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$AI-powered identity verification$q$, $q$IDV uses video and facial recognition to verify customer identity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Fraud Detection Pro$q$, $q$Machine-learning-based fraud prevention applied to transactions in real time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Intelligent Acceptance$q$, $q$AI system that optimizes transaction approval rates to reduce false declines.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Multi-currency Business Account$q$, $q$Hold and manage funds across multiple currencies from a single account.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Global payouts$q$, $q$Send funds to recipients internationally through a unified payouts API.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Direct card network membership across Visa, Mastercard, and other networks in many markets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Interchange++ pricing offers more fee transparency than blended-rate processors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Single API covering payments, issuing, identity verification, and fraud prevention$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Built for global, multi-currency, high-volume enterprise operations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Enterprise pricing is not fully public and requires a sales conversation for an accurate quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Primarily designed for larger merchants; may be more than smaller businesses need$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Integration and onboarding can be more involved than plug-and-play payment providers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Standard flat-rate pricing for non-European cards is higher than some competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$What is Checkout.com?$q$, $q$Checkout.com is a global payment processing company offering a payment gateway, card acquiring, card issuing, identity verification, and fraud prevention through a single API.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$How much does Checkout.com charge per transaction?$q$, $q$Published flat rates are 0.95% plus $0.20 for European cards and 2.90% plus $0.20 for non-European cards; larger merchants can negotiate custom interchange++ rates.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Where is Checkout.com headquartered?$q$, $q$Checkout.com is headquartered in London, United Kingdom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Is Checkout.com a bank?$q$, $q$No, Checkout.com is a payment services provider and acquirer, not a licensed bank, though it holds direct membership with major card networks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$What is interchange++ pricing?$q$, $q$Interchange++ separates a transaction's cost into the underlying interchange fee, the card network's scheme fee, and the processor's own markup, giving merchants visibility into each component.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Global enterprise ecommerce$q$, $q$Large online retailers use Checkout.com to accept payments across multiple currencies and card networks worldwide.$q$, $q$Enterprise ecommerce and retail companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Marketplaces and platforms$q$, $q$Multi-sided marketplaces use Checkout.com's payments and payouts APIs to collect from buyers and disburse to sellers.$q$, $q$Marketplace and platform businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Fraud and risk management$q$, $q$Merchants use Fraud Detection Pro and Intelligent Acceptance to reduce chargebacks while maximizing approval rates.$q$, $q$Risk and payments operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Standard (European cards)$q$, $q$0.95% + $0.20 per transaction$q$, $q$Per transaction$q$, NULL, $q$["Flat-rate pricing","Payment gateway and acquiring","Access to Flow checkout"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Standard (non-European cards)$q$, $q$2.90% + $0.20 per transaction$q$, $q$Per transaction$q$, NULL, $q$["Flat-rate pricing","Payment gateway and acquiring","Access to Flow checkout"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$Enterprise$q$, $q$Custom (interchange + markup)$q$, $q$Custom$q$, NULL, $q$["Interchange++ pricing","Volume-based negotiated rates","Dedicated account support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Checkout.com was founded in 2009 as Opus Payments by Guillaume Pousaz and rebranded to Checkout.com in 2012. Headquartered in London, the company grew into a global payments infrastructure provider with direct membership status across major card networks including Visa, Mastercard, American Express, UnionPay, and JCB, letting it operate as both a payment gateway and acquirer in many regions.$q$, $q$The company has raised approximately $3.8 billion, peaked at a $40 billion valuation in 2022, and reported reaching profitability in 2024, with a later valuation of roughly $12 billion reflecting broader fintech market corrections. It employs around 2,000 people across roughly 19 offices worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Checkout.com's core product, Flow, provides a customizable prebuilt payment interface, while Issuing lets businesses create physical and virtual cards. IDV offers AI-powered video identity verification, and Fraud Detection Pro applies machine learning to catch fraudulent transactions.$q$, $q$Intelligent Acceptance uses AI to optimize payment authorization rates, Business Account provides multi-currency fund management, and Payouts enables global disbursements — together forming a single API-driven platform for accepting, managing, and moving money.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Checkout.com uses an interchange++ pricing model that separates interchange, network scheme fees, and its own markup for transparency. Published flat rates are 0.95% plus $0.20 per transaction for European cards and 2.90% plus $0.20 for non-European cards.$q$, $q$Enterprise merchants with sufficient volume can negotiate custom interchange-plus pricing, sometimes as low as interchange plus 0.10%-0.40% and $0.08 per transaction, but exact enterprise rates require contacting the Checkout.com sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23986f65-446a-4255-8e2d-e265951f2262', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Multi-user accounts with 2FA$q$, $q$User registration, profiles, and two-factor authentication with role-based access control.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Albums and tagging$q$, $q$Organize uploaded images and videos into albums, categories, and tags.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Multi-tenant hosting$q$, $q$Run multiple independent branded media sites from a single Chevereto installation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Object storage and CDN integration$q$, $q$Connect to Amazon S3, Google Cloud Storage, Alibaba Cloud, and CDNs for scalable media delivery.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Granular privacy controls$q$, $q$Set visibility rules for individual images, albums, or entire user accounts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$30+ language support$q$, $q$Built-in internationalization for a broad range of interface languages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Extensive API$q$, $q$Programmatic upload and management API for custom integrations and automation.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Full data ownership through self-hosting instead of relying on a third-party image host$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Mature codebase with active development dating back to 2007$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Flexible storage options including CDN and major cloud object storage providers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Free open-source edition available alongside paid Lite/Pro tiers for more features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Paid features and priority support are gated behind Lite/Pro commercial licenses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Requires server management skills and ongoing maintenance since it's self-hosted$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$License subscription needed to keep receiving updates beyond the version already installed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Not a managed SaaS option, so uptime and scaling are the operator's responsibility$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Is Chevereto free?$q$, $q$Yes, Chevereto has a free, open-source edition licensed under AGPLv3. Paid Lite and Pro editions with additional features are available under a separate commercial license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Can Chevereto be self-hosted?$q$, $q$Yes, Chevereto is designed to be self-hosted on your own server, VPS, or hosting control panel, and can be deployed with Docker.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$What database does Chevereto require?$q$, $q$Chevereto requires MySQL or MariaDB, and optionally supports Redis for caching.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Does Chevereto support cloud storage?$q$, $q$Yes, Chevereto integrates with Amazon S3, Google Cloud Storage, Alibaba Cloud, and CDN services for storing and delivering media.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Who created Chevereto?$q$, $q$Chevereto was created by Rodolfo Berríos, a software engineer based in Concepción, Chile, with development dating back to 2007.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Private community image hosting$q$, $q$Forums and online communities self-host Chevereto to give members a dedicated image and video sharing space.$q$, $q$Community managers and forum operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$White-label media platforms$q$, $q$Agencies use Chevereto's multi-tenant capability to offer branded image-hosting sites to multiple clients from one installation.$q$, $q$Web agencies and hosting providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Personal or organizational media archive$q$, $q$Individuals and small teams self-host Chevereto to retain full control over uploaded photos and videos.$q$, $q$Individuals and small businesses wanting full data ownership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open source, AGPLv3 licensed","Core image/video hosting","Self-hosted","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Lite$q$, $q$Paid (see chevereto.com/pricing)$q$, $q$Subscription$q$, NULL, $q$["Proprietary license","Additional features over Free edition","Includes updates during active subscription"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$Pro$q$, $q$Paid (see chevereto.com/pricing)$q$, $q$Subscription$q$, NULL, $q$["Proprietary license","Full feature set including multi-tenant hosting","Priority support during active subscription"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chevereto is self-hosted image and video hosting software created by Rodolfo Berríos, in development since 2007 and formalized as a company in 2012. It lets operators run their own private, fully branded media-sharing website on their own servers, similar in concept to Imgur or Flickr but without depending on a third-party host.$q$, $q$The software is a PHP application that can be deployed via Docker, a VPS, or standard hosting control panels, and is available under both an open-source AGPLv3 license (Free edition) and a proprietary commercial license (Lite and Pro editions) for teams that want additional features and support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chevereto supports multi-user accounts with two-factor authentication and role-based access, media organization through albums and tags, and multi-tenant hosting so one installation can serve multiple independent sites. It integrates with CDNs and object storage providers like Amazon S3, Google Cloud Storage, and Alibaba Cloud.$q$, $q$The platform supports over 30 languages and exposes an extensive API for programmatic uploads, making it suitable for both direct end-user hosting sites and integrations with other applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Chevereto Free edition is open source (AGPLv3) and free to self-host indefinitely. Chevereto Lite and Pro are paid, proprietary-licensed editions sold as subscriptions; a license key grants updates and support during the active subscription period, and any version released during that time can be used perpetually afterward.$q$, $q$Exact Lite and Pro pricing is published on chevereto.com and varies by plan; prospective buyers should check the current rates directly, since Chevereto periodically adjusts pricing for new subscribers while honoring existing subscribers' locked-in rates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08cb66ce-1814-4087-a29d-3578403ad173', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Chunked large-file uploads$q$, $q$Automatically splits big files into chunks during upload to reduce network failure risk.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$ShareX integration$q$, $q$Works out of the box with the popular ShareX screenshot and upload utility.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$S3-compatible storage$q$, $q$Supports S3-compatible object storage backends for scalable file storage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Configurable admin dashboard$q$, $q$Change instance settings like rate limits, max file size, and allowed extensions from the web UI.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Albums, tags, and quotas$q$, $q$Organize uploads into albums and folders, tag files, and set per-user storage quotas.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Built-in URL shortener$q$, $q$Shorten links directly within the same self-hosted instance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$API keys$q$, $q$Generate API keys to upload and manage files programmatically.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Full data ownership through self-hosting rather than a third-party uploader$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Native ShareX, browser extension, and iOS shortcut support for fast uploads$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Actively maintained with a real GitHub community and Docker-based deployment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Requires your own server or VPS and ongoing maintenance to self-host$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$No official managed hosting or paid enterprise support option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Feature set has changed across major versions (lolisafe to Chibisafe), requiring migration care on upgrades$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Support is community-based via GitHub rather than a guaranteed SLA$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Is Chibisafe free?$q$, $q$Yes, Chibisafe is completely free and open source under the MIT license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Is Chibisafe related to lolisafe?$q$, $q$Yes, Chibisafe is the TypeScript rewrite and rebrand of the lolisafe project, starting with version 4.0.0, maintained by the same developer, Pitu.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Does Chibisafe support ShareX?$q$, $q$Yes, Chibisafe supports ShareX out of the box, making it easy to upload screenshots and files directly from Windows.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Can Chibisafe use S3 storage?$q$, $q$Yes, Chibisafe supports S3-compatible object storage as a backend for uploaded files.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$How do I deploy Chibisafe?$q$, $q$Chibisafe is most commonly deployed via Docker, though it can also run directly with Node.js on a Linux server such as Debian.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Private file and image sharing$q$, $q$Individuals self-host Chibisafe to have full control over uploaded files instead of relying on public file hosts.$q$, $q$Privacy-conscious individuals and power users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Community and Discord server file hosting$q$, $q$Community admins run Chibisafe to give members a dedicated, moderated place to upload and share images and files.$q$, $q$Community and Discord server administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$Developer-integrated uploads$q$, $q$Developers use Chibisafe's API to build custom upload workflows, such as ShareX-based screenshot sharing.$q$, $q$Developers and technical self-hosters$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chibisafe is a free, open-source, self-hosted file and image uploader written in TypeScript, maintained by developer Pitu. It is the TypeScript rewrite and rebrand of the earlier lolisafe project, with Chibisafe representing version 4.0.0 and later of that same codebase, dating back to around 2017.$q$, $q$The service accepts virtually any file type and returns a shareable link, giving operators a private alternative to public file-sharing services, with support for public, registered-user, and invite-only access modes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chibisafe includes automatic chunking for large file uploads, API keys for programmatic access, and out-of-the-box ShareX support alongside a dedicated browser extension and iOS shortcut. Its admin dashboard lets operators configure rate limits, file size caps, allowed extensions, and other instance settings entirely from the web UI.$q$, $q$Additional features include S3-compatible storage support, a masonry gallery view, albums and folders, snippet/gist sharing, tagging, per-user quotas, and a built-in URL shortener.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Chibisafe is completely free and released under the MIT license. There is no paid tier or official managed hosting offering; users self-host the software on their own server or VPS, typically via Docker.$q$, $q$Because there's no commercial vendor behind it, support is community-driven through the project's GitHub repository rather than a paid support contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e4812bd-f938-4e90-be82-f06e39de6ab3', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Slack-native onboarding$q$, $q$New hires can complete the entire onboarding flow through Slack, not just the web portal.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Preboarding pages$q$, $q$Build welcome pages with text, images, files, and checklists for hires before their start date.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Sequences and drip-fed tasks$q$, $q$Schedule onboarding tasks to release over time or trigger on completion of previous steps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Automated account provisioning$q$, $q$Automatically create accounts in tools like Slack, Google Workspace, Asana, and GitHub for new hires.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Knowledge base and courses$q$, $q$Searchable resource library and structured courses for self-paced ramp-up.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Badges and gamification$q$, $q$Reward task completion to sustain engagement during onboarding.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Multilingual interface$q$, $q$Available in English, Dutch, Portuguese, German, Turkish, French, Spanish, and Japanese.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Free, self-hosted core with no cost for organizations that can manage their own infrastructure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Deep native Slack integration alongside a full-featured web portal$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Open source (AGPLv3) with full control over onboarding data and the ability to customize the code$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Automated account provisioning reduces manual IT setup work for new hires$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Free plan support is limited to community GitHub issues, with no guaranteed response time$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Smaller ecosystem and fewer third-party integrations than large HR SaaS suites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Priority support requires the paid €249/month plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Is ChiefOnboarding free?$q$, $q$Yes, ChiefOnboarding has a free, self-hosted plan with community support. A paid Support plan at €249/month adds priority email support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Does ChiefOnboarding work with Slack?$q$, $q$Yes, new hires can complete the entire onboarding process through Slack, with full feature parity to the web portal.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Is ChiefOnboarding open source?$q$, $q$Yes, ChiefOnboarding is open source under the AGPLv3 license, and the code is available on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Can ChiefOnboarding automate account creation?$q$, $q$Yes, it can automatically provision accounts in tools like Slack, Google Workspace, Asana, and GitHub as part of the onboarding sequence.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$What languages does ChiefOnboarding support?$q$, $q$ChiefOnboarding's interface supports English, Dutch, Portuguese, German, Turkish, French, Spanish, and Japanese.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Remote-first company onboarding$q$, $q$Distributed teams that live in Slack use ChiefOnboarding to run onboarding entirely within their existing chat workflow.$q$, $q$Remote and distributed companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Self-hosted HR data control$q$, $q$Organizations with data residency or privacy requirements self-host ChiefOnboarding to keep onboarding data on their own servers.$q$, $q$HR and IT teams with data control requirements$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Automated new-hire account setup$q$, $q$Growing startups use sequences and provisioning integrations to automatically create tool accounts for each new hire.$q$, $q$Startups scaling their hiring process$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Free$q$, $q$€0/month$q$, $q$N/A$q$, NULL, $q$["Self-hosted","Community support via GitHub issues","Full onboarding feature set"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$Support$q$, $q$€249/month$q$, $q$Annual, excl. VAT$q$, NULL, $q$["Self-hosted","Priority email support (typically under 2 hours)","Full onboarding feature set"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ChiefOnboarding is a free and open-source employee onboarding platform founded by Stan Triepels in 2016. New hires can complete onboarding entirely through Slack or a standalone web portal, both with full feature access, and the software can be self-hosted or deployed via the project's managed hosting option.$q$, $q$Licensed under AGPLv3, ChiefOnboarding gives HR and IT teams full control over onboarding data and workflows, positioning it as an alternative to closed SaaS onboarding platforms for organizations that want to self-host or customize the codebase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Employers build preboarding pages to welcome new hires before their start date, and use sequences to drip-feed onboarding tasks over time or trigger them based on prior task completion. Automated account provisioning integrates with tools like Slack, Google Workspace, Asana, and GitHub to create new-hire accounts automatically.$q$, $q$A built-in knowledge base and course system helps new hires ramp up at their own pace, and badges/gamification features are included to keep engagement high during the first weeks. The interface is available in eight languages, supporting multi-region onboarding programs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ChiefOnboarding offers a Free plan at €0/month for self-hosting with community support through GitHub issues, aimed at teams with their own IT capacity. The Support plan costs €249/month, billed annually and excluding VAT, and adds priority email support with typical response times under two hours while remaining self-hosted.$q$, $q$Both plans keep data on the customer's own infrastructure; ChiefOnboarding also offers a managed hosting option outside the self-hosted pricing above for organizations that don't want to run their own servers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('244c73b2-067b-49f8-9f82-b83dd0e0dfce', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Serverless peer-to-peer architecture$q$, $q$Uses WebRTC for direct peer connections with no dedicated backend chat server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Ephemeral messaging$q$, $q$Messages are never persisted to disk and are cleared from memory when a user leaves a room.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$No accounts required$q$, $q$Users can join a chat room instantly without signing up or creating an account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Encrypted file transfer$q$, $q$Supports file transfers of unlimited size, encrypted client-side before sending.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Video, audio, and screen sharing$q$, $q$Multi-peer video and audio calls plus screen sharing within a room.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Public and private rooms$q$, $q$Rooms use random UUIDs by default and can be shared privately or left open publicly.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$No tracking or telemetry$q$, $q$No analytics, tracking, or telemetry of any kind is built into the application.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Strong privacy design: no server-side storage, no accounts, no tracking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Completely free and open source under GPL v2$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$No sign-up friction; join a room and start chatting immediately$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Supports rich media including video calls, screen sharing, and unlimited file size transfers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Peer-to-peer connection reliability depends on network conditions and NAT/firewall traversal$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$No message history or persistence by design, so nothing can be recovered after leaving a room$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$No built-in user directory, workspace, or admin/moderation controls$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Not intended as a replacement for persistent team chat or enterprise messaging tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Is Chitchatter free?$q$, $q$Yes, Chitchatter is completely free, open source, and requires no account or subscription to use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Does Chitchatter store my messages?$q$, $q$No, messages are never persisted to disk and are cleared from memory as soon as you leave a chat room.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Does Chitchatter require a server?$q$, $q$Chitchatter has no dedicated backend chat server; it relies on WebRTC peer-to-peer connections, using public WebTorrent trackers for discovery and STUN/TURN servers only as a fallback.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Can Chitchatter be self-hosted?$q$, $q$Yes, since Chitchatter is a client-side, largely serverless open-source application, anyone can host their own instance of it.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Does Chitchatter support video calls?$q$, $q$Yes, Chitchatter supports audio and video calling as well as screen sharing between multiple peers in a room.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Throwaway private conversations$q$, $q$Individuals create a one-off room to have a quick, private conversation without setting up an account.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Ephemeral sensitive communications$q$, $q$Journalists, researchers, or activists use Chitchatter for conversations that leave no server-side record.$q$, $q$Journalists, researchers, and privacy-focused professionals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$Self-hosted P2P chat experimentation$q$, $q$Developers self-host their own Chitchatter instance to study or build on a lightweight, serverless WebRTC chat implementation.$q$, $q$Developers and open-source contributors$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chitchatter is a free, open-source, peer-to-peer chat application created by developer Jeremy Kahn and hosted publicly at chitchatter.im, with source available on GitHub under the GPL v2 license. It is described as serverless, decentralized, and ephemeral: there is no dedicated Chitchatter backend server, no accounts, and no persisted message history.$q$, $q$Peer connections are established via WebRTC, using public WebTorrent trackers for peer discovery and STUN/TURN relay servers only as a fallback when a direct connection isn't possible, keeping the architecture lightweight and largely serverless.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Within a chat room, Chitchatter supports text messaging, audio and video calls, and screen sharing between multiple peers. File transfers of unlimited size are supported, with files encrypted client-side before being sent over the peer-to-peer connection.$q$, $q$Rooms use random, client-generated UUIDs as names by default and can be shared privately via URL or left open as public rooms. Since nothing is stored server-side, there is no analytics, tracking, or telemetry, and messages are cleared from memory the moment a user leaves a room.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Chitchatter is completely free to use at chitchatter.im, with no accounts, subscriptions, or paid tiers. Because it's open source and largely serverless, anyone can also self-host their own instance of the client-side application at no licensing cost.$q$, $q$There is no commercial entity monetizing Chitchatter, so all functionality, including video calls and unlimited-size file transfer, is available without payment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dd982ac6-15fa-4c92-86fd-7b3367a55768', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Free restaurant ordering app$q$, $q$Restaurants place and track orders with multiple suppliers from one app, on iOS, Android, or web.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Real-time digital catalog$q$, $q$Suppliers maintain a live product catalog that reps and customers reference while ordering.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$AI-powered order processing$q$, $q$Lets sales reps log orders quickly with reduced manual data entry using AI assistance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Smart AI alerts$q$, $q$Flags upsell opportunities or customer churn risk based on changes in ordering behavior.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Sales Rep mobile app$q$, $q$Dedicated app for field sales reps to manage accounts and log orders while visiting customers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Prospecting tools$q$, $q$Lets reps scan a restaurant's menu to suggest relevant products when pursuing new accounts.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Free for restaurants, removing cost as a barrier to adopting digital ordering$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$AI-assisted order logging and alerts help distributor sales teams work more efficiently$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Consolidates multi-supplier ordering into a single app for restaurant staff$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Backed by significant funding and unicorn status, suggesting platform stability and continued investment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Supplier pricing is not publicly published and requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Does not include built-in payment processing or invoicing as a core feature$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Value is strongest where both a restaurant's suppliers and the restaurant itself are on Choco$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Primarily focused on food and beverage distribution, not a general-purpose B2B ordering tool$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Is Choco free for restaurants?$q$, $q$Yes, the Choco app is free for restaurants to order from their suppliers, with no listed fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$How much does Choco cost for suppliers?$q$, $q$Choco uses custom pricing for suppliers and distributors based on usage and features, with third-party estimates suggesting roughly $20-$25 per customer account per month; exact pricing requires a sales quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Does Choco process payments?$q$, $q$Choco's core platform is focused on order and catalog management rather than payment processing or invoicing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Where is Choco headquartered?$q$, $q$Choco is headquartered in Berlin, Germany, and was founded there in 2018.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Does Choco have a mobile app?$q$, $q$Yes, Choco offers apps for both restaurants (iOS and Android) and a separate Sales Rep app for distributor field sales teams.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Multi-supplier restaurant ordering$q$, $q$Restaurants use the free Choco app to order from all their food and beverage suppliers in one place instead of separate calls or texts.$q$, $q$Independent restaurants and restaurant groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Distributor sales team enablement$q$, $q$Food and beverage distributors use Choco's catalog, AI order processing, and alerts to help sales reps manage and grow accounts.$q$, $q$Food and beverage wholesalers and distributors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$New account prospecting$q$, $q$Distributor sales reps use Choco's menu-scanning prospecting tools to identify and pitch relevant products to potential new restaurant customers.$q$, $q$Distributor field sales representatives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Restaurant (Free)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Order from multiple suppliers in one app","Order tracking","iOS, Android, and web access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$Supplier/Distributor$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Digital catalog","AI-powered order processing","Smart alerts","Sales Rep app","Prospecting tools"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Choco is a B2B technology platform for the food and beverage supply chain, founded in 2018 in Berlin, Germany by Daniel Khachab, Rogerio Da Silva Yokomizo, and Julian Hammer. It connects restaurants with the distributors that supply them, replacing phone- and text-based ordering with a digital ordering and catalog platform.$q$, $q$The company has raised over $300 million in venture funding and reached unicorn status at a roughly $1.2 billion valuation, with backers including Bessemer Venture Partners, Coatue, and Insight Partners.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Restaurants use Choco's free mobile and web app to place and track orders with multiple suppliers from a single place, reducing errors compared to phone or text ordering. Distributors and their sales teams get a real-time digital catalog, AI-assisted order logging, and smart alerts that flag upsell opportunities or churn risk based on changes in ordering patterns.$q$, $q$A dedicated Sales Rep app lets field reps manage accounts, browse catalogs, and log orders from their phone while visiting customer restaurants, and prospecting tools let reps scan a restaurant's menu to suggest relevant products when courting new accounts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0f1e2f2-b93c-47f1-8795-6a8abd9a82c6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Choco's restaurant-facing ordering app is free to use, with no published fees for restaurants. Suppliers and distributors pay for the platform under a custom pricing model based on usage, number of users, and selected features, rather than fixed published tiers.$q$, $q$Third-party estimates suggest supplier pricing can fall roughly in the $20-$25 per customer account per month range, but this is not an officially published rate, and suppliers need to contact Choco's sales team for an exact quote.$q$]::text[], 2);
