-- Enrichment marathon batch: Checkmarx, Checkmk, Checkout.com, Chevereto, Chibisafe, ChiefOnboarding, Chitchatter, Choco

-- ── Checkmarx ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Checkmarx is an enterprise application security testing platform combining SAST, SCA, DAST, and API security scanning in the unified Checkmarx One cloud platform.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$900+ employees$q$, company_size),
  headquarters = COALESCE($q$Ramat Gan, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Checkmarx Review: Features, Pricing & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Checkmarx's SAST, SCA, DAST, and API security modules work inside Checkmarx One, plus pricing structure and how it compares for enterprise AppSec.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Checkmarx is an application security testing (AppSec) company founded in 2006 by Maty Siman and Emmanuel Benzaquen. It is headquartered in Ramat Gan, Israel, with a major U.S. presence in Atlanta, Georgia, and additional offices across the UK, France, Portugal, India, and Singapore. The company employs more than 900 people and was acquired by private equity firms Hellman & Friedman and TPG in April 2020 for approximately $1.15 billion; its flagship cloud platform, Checkmarx One, reportedly surpassed $150 million in annual recurring revenue in late 2025. Checkmarx's core product is Checkmarx One, a cloud-based application security platform that consolidates multiple scanning technologies into a single interface: Static Application Security Testing (SAST) analyzes source code for vulnerabilities pre-deployment; Software Composition Analysis (SCA) identifies vulnerable and non-compliant open-source dependencies and generates software bills of materials (SBOMs); Dynamic Application Security Testing (DAST) tests running applications for exploitable vulnerabilities; API Security scans and inventories API endpoints for exposure risks; and additional modules cover Infrastructure-as-Code (IaC) scanning, container security, and supply-chain security. Checkmarx has also introduced AI-oriented capabilities, including tooling aimed at securing AI-generated code and agentic development workflows. The platform integrates with common CI/CD pipelines, source control systems (GitHub, GitLab, Bitbucket, Azure DevOps), and ticketing tools, and is positioned for organizations running DevSecOps programs at scale. Checkmarx does not publish standard list pricing. Instead, customers select the specific modules relevant to their attack surface (for example, SAST plus SCA, or a full-platform bundle including DAST and API Security) and receive a custom quote, typically scoped to number of developers, scan volume, and contract length. Buyers who bundle multiple modules or commit to multi-year terms commonly negotiate lower effective per-module pricing than standalone purchases; organizations with 50 or more developers often see the largest discounts. Because pricing is not transparent, prospective customers generally need to engage the Checkmarx sales team to get an accurate cost estimate, which can make budget comparison against competitors more difficult than with vendors that publish tiered pricing. Checkmarx is best suited to mid-size and large enterprises, particularly those in regulated industries or building software supply chains, that need a single consolidated AppSec vendor rather than assembling point solutions from multiple providers. Smaller teams or startups with limited security budgets may find the platform's modular licensing and lack of public self-service pricing to be a barrier compared with lighter-weight, self-serve AppSec tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '72d98dd7-ff9a-4d03-9e76-84a11ee4dcec';

