-- ── Checkout.com ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Checkout.com is a global payment processing platform providing payment gateway, acquiring, card issuing, and fraud prevention infrastructure for enterprise merchants.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$0.95% + $0.20 per transaction (European cards)$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$2,000+ employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Checkout.com Review: Payments Platform, Fees & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how Checkout.com's payment gateway, card acquiring, and issuing platform works, its interchange++ pricing model, fees, and who it's built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Checkout.com is a financial technology company that provides payment processing infrastructure for enterprise merchants. It was originally founded in 2009 as Opus Payments by Guillaume Pousaz, a Swiss entrepreneur, and rebranded to Checkout.com in 2012. The company is headquartered in London, United Kingdom, and by the mid-2020s employed roughly 2,000 people across around 19 global offices. Checkout.com became a principal member of Visa and Mastercard by 2013 and later secured direct membership status with UnionPay, Diners, Discover, American Express, and JCB, allowing it to act as both a payment gateway and an acquirer in many markets rather than relying entirely on third-party banking partners. The company has raised roughly $3.8 billion in total funding across multiple rounds, including a $230 million Series A in 2019 and a $1 billion Series D in January 2022 that valued the company at $40 billion, making it briefly Europe's most valuable fintech startup at the time. Following broader fintech valuation corrections, the company's valuation was later marked down to approximately $12 billion by 2025, around the same time the company reported reaching profitability in 2024. Checkout.com has also made several acquisitions to expand its capabilities, including Pin Payments (2020), ProcessOut, Icefire (2021), and identity-verification company Ubble (2022). Its product suite includes Flow, a customizable prebuilt payment interface for websites; Issuing, a platform for creating physical and virtual payment cards; IDV, an AI-powered video identity verification tool with facial recognition; Fraud Detection Pro, a machine-learning-based transaction fraud prevention system; Intelligent Acceptance, an AI system designed to optimize payment authorization/approval rates; Business Account, a multi-currency fund management tool for merchants; and Payouts, for sending funds to recipients globally. Checkout.com uses an interchange++ pricing model, which separates the underlying interchange fee, card network scheme fee, and the company's own markup so merchants can see each cost component rather than a single blended rate. Published flat-rate pricing for standard merchants is 0.95% plus $0.20 per transaction for European cards and 2.90% plus $0.20 per transaction for non-European cards; qualifying Enterprise customers with higher volume can negotiate down to interchange plus a markup as low as roughly 0.10%-0.40% plus $0.08 per transaction. Because exact enterprise pricing depends on transaction volume, business model, and geographic footprint, merchants generally need to contact Checkout.com's sales team for a tailored quote. The platform is aimed primarily at mid-size to large global enterprises, marketplaces, and platforms that need a single API to accept payments, issue cards, and manage risk across multiple regions and currencies, rather than smaller merchants who may be better served by simpler, flat-fee payment providers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '23986f65-446a-4255-8e2d-e265951f2262';

