-- ── Chevereto ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chevereto is self-hosted image and video hosting software for building a private, fully customizable media-sharing website similar to Imgur or Flickr.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Concepción, Chile$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chevereto Review: Self-Hosted Image Hosting Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Chevereto lets you self-host your own image and video hosting site. See its free open-source edition, paid Lite/Pro licenses, and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chevereto is self-hosted image and video hosting software created by Rodolfo Berríos, a software engineer based in Concepción, Chile. The project has been in development since 2007, making it one of the longer-running self-hosted media platforms, and was formally established as a company in 2012. Chevereto lets individuals, communities, and businesses run their own private image and video sharing website, comparable in concept to Imgur or Flickr, but fully under the operator's control since it runs on the operator's own server rather than a third-party cloud service. The software is a PHP application (with JavaScript and CSS for the frontend) that requires a web server, a MySQL or MariaDB database, and optionally Redis for caching, and it can be deployed via Docker, on a VPS, or through control panels like cPanel and Plesk. Chevereto is distributed under two licensing models. The Free edition is open source under the AGPLv3 license and available on GitHub, providing core image/video hosting functionality at no cost. Chevereto Lite and Chevereto Pro are distributed under a proprietary commercial license: buyers purchase a subscription that grants a license key with access to updates, bug fixes, and support for a limited period, but any version released during an active subscription can continue to be used perpetually afterward, even if the subscription lapses. Key features across editions include multi-user accounts with registration, user profiles, two-factor authentication, and role-based access control; albums, tags, and categories for organizing media; multi-tenant capability so a single installation can host multiple independent branded sites; granular privacy controls for content visibility; performance features including CDN support and integration with object storage services like Amazon S3, Google Cloud Storage, and Alibaba Cloud; support for over 30 languages; and an extensive API for programmatic uploads and integrations. Because Chevereto is self-hosted, adopters are responsible for their own server infrastructure, security patching, and backups, which gives full data ownership but requires more technical involvement than a managed SaaS image host. It's commonly used by web agencies building white-label media-sharing platforms for clients, community and forum operators who want their own private image host instead of relying on third-party services, and individuals or small teams who want full control over uploaded content and its long-term availability rather than depending on a hosting service that could change its terms or shut down.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '08cb66ce-1814-4087-a29d-3578403ad173';

