-- ── Chibisafe ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chibisafe is a free, open-source, self-hosted file and image uploader written in TypeScript that gives you a private, ShareX-compatible vault with shareable links.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chibisafe Review: Self-Hosted File Uploader Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Chibisafe is a free, open-source, self-hosted file vault with S3 support, ShareX integration, and an API. See its features and setup requirements.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chibisafe is a free, open-source, self-hosted file and image uploader written in TypeScript, maintained by a developer known as Pitu. It is the modern continuation of an earlier project called lolisafe; version 4.0.0 and later were rewritten and rebranded as Chibisafe, with lolisafe representing the earlier 3.x lineage of the same codebase. The project traces back to around 2017 and has accumulated a few thousand stars on GitHub, with an active community of self-hosters. Chibisafe accepts file uploads of essentially any type and returns a shareable link, functioning as a private alternative to public file-sharing or image-hosting services. It supports three access modes: public mode (anyone can upload), user accounts mode (registered users upload to their own space), and invite-only mode (uploads restricted to invited users). Large files are automatically chunked during upload to reduce the chance of network failures interrupting a transfer, and users can generate API keys to interact with the service programmatically, which enables integration with tools like ShareX, a popular Windows screenshot and file-upload utility, as well as a dedicated browser extension for uploading content directly from web pages and an iOS shortcut for uploading from Apple devices. The platform ships with an administrative dashboard that lets operators configure most instance settings directly from the web UI, including the instance name, rate limits, maximum file size, accepted file extensions, and meta descriptions, without needing to edit configuration files by hand. Additional features include S3-compatible object storage support for scalable file storage, a masonry-style gallery for browsing uploaded media, albums and folders with dedicated shareable links, snippet/gist creation for sharing text content, file tagging, per-user storage quotas, and a built-in URL shortener. Chibisafe is released under the MIT license and is typically deployed via Docker, though it can also run directly with Node.js; self-hosting recommendations include a recent Linux distribution (Debian is commonly recommended) with Node.js 12.18.2 or later and build-essential tools installed. As with most self-hosted open-source projects, there is no official managed hosting or paid support tier; users are responsible for their own server, updates, and backups, and support comes primarily through the GitHub repository's issues and community channels rather than a commercial SLA. It is best suited to individuals, Discord/community server admins, and developers who want a private, ShareX-compatible file host they fully control, rather than relying on third-party public file-sharing services with unclear data retention policies.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5e4812bd-f938-4e90-be82-f06e39de6ab3';

