-- ── ChiefOnboarding ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ChiefOnboarding is an open-source employee onboarding platform where new hires complete preboarding tasks, sequences, and training through Slack or a web portal.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Dutch$q$, $q$Portuguese$q$, $q$German$q$, $q$Turkish$q$, $q$French$q$, $q$Spanish$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$ChiefOnboarding Review: Open-Source Onboarding Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$ChiefOnboarding is a free, self-hosted, open-source employee onboarding platform with deep Slack integration. Compare its pricing plans and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ChiefOnboarding is a free and open-source employee onboarding platform founded by Stan Triepels in 2016. It lets new hires complete their onboarding process entirely through Slack or through a standalone web portal, with both interfaces offering full feature parity so companies can choose whichever fits their existing workflow. The software is licensed under AGPLv3 and can be self-hosted on a company's own infrastructure or run through the company's managed hosting option, with no lock-in between the two deployment models. Core functionality includes preboarding pages, where employers build informational pages with text, images, files, and checklists to welcome new hires before their official start date; sequences and drip-fed tasks, which let HR teams schedule to-do items to release over time or trigger automatically based on completion of a prior task; automated account provisioning, which integrates with third-party tools such as Slack, Google Workspace, Asana, and GitHub to automatically create user accounts for new employees as part of the onboarding flow; a knowledge base and courses module, where new hires can search a resource library and work through structured courses at their own pace; and badges and gamification features designed to reward task completion and sustain engagement during the first weeks on the job. The platform supports eight interface languages: English, Dutch, Portuguese, German, Turkish, French, Spanish, and Japanese, making it usable for onboarding programs spanning multiple regions. ChiefOnboarding's pricing follows a simple two-tier model. The Free plan costs €0 per month and covers self-hosting the software on your own infrastructure, with support limited to community channels via GitHub issues; this plan is aimed at organizations with an internal IT team capable of managing their own deployment without vendor assistance. The Support plan costs €249 per month, billed annually and excluding VAT, and adds priority email support with a response time generally under two hours, while still being self-hosted — this plan targets organizations that want to retain full control of their onboarding data on their own servers but also want responsive vendor assistance when issues arise. EU-based businesses purchasing the Support plan must provide a valid VAT ID. Because it's open source, companies with development resources can also inspect, modify, or extend the codebase directly. ChiefOnboarding is best suited to remote-first and distributed companies that already run their internal communication through Slack and want onboarding tightly integrated into that workflow, as well as organizations that prioritize owning and controlling their onboarding and HR data on self-managed infrastructure rather than depending on a third-party SaaS HR platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '244c73b2-067b-49f8-9f82-b83dd0e0dfce';

