-- ── Chitchatter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chitchatter is a free, open-source, serverless peer-to-peer chat app offering encrypted messaging, file transfer, and video calls with nothing stored on a server.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chitchatter Review: Serverless P2P Encrypted Chat$q$, seo_title),
  seo_meta_description = COALESCE($q$Chitchatter is a free, open-source, peer-to-peer chat app with no servers, no accounts, and no message history. See how it works and its features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chitchatter is a free, open-source, peer-to-peer communication application created by developer Jeremy Kahn and available at chitchatter.im, with source code hosted on GitHub under the jeremyckahn/chitchatter repository. It is licensed under GPL v2. The application is described by its own maintainers as serverless, decentralized, and ephemeral: it runs entirely as a client-side web app with no dedicated Chitchatter backend server, and no user accounts or sign-up process are required to use it. To establish connections between users, Chitchatter relies on WebRTC for direct peer-to-peer data channels, using public WebTorrent trackers to help peers discover each other, and falling back to STUN/TURN relay servers only when a direct peer-to-peer connection cannot be established due to restrictive network conditions such as symmetric NATs or firewalls. Because there is no central Chitchatter server storing data, the application has no analytics, tracking, or telemetry of any kind built in. Messages exchanged in a chat room are never persisted to disk on either party's device; when a user leaves a room, that room's message history is cleared from memory and cannot be recovered by either party or by a third party, since it was never stored anywhere in the first place. Room names are, by default, random UUIDs generated entirely on the client side, and users share a room's URL out-of-band (for example, over a separate secure channel) with anyone they want to invite. Rooms can be public, where anyone who has or guesses the room URL can join, or effectively private, where access is limited to those who receive the specific room link. Within a room, Chitchatter supports text messaging, audio and video calling, and screen sharing between multiple peers simultaneously, and it supports file transfers of unlimited size, with files encrypted client-side before being sent over the peer-to-peer connection. Because Chitchatter is a static, client-rendered web application with no required backend infrastructure beyond publicly available WebRTC signaling and relay servers, it can also be self-hosted by anyone who wants to run their own instance rather than relying on the public chitchatter.im deployment, which is useful for organizations or individuals wanting additional assurance about which signaling infrastructure is being used. Chitchatter is best suited to privacy-conscious individuals who want a throwaway, no-signup chat room for a single conversation or file transfer, to journalists, researchers, or activists who need ephemeral communications that leave no server-side record, and to developers interested in a lightweight, self-hostable, open-source example of a fully client-side WebRTC chat application. It is not designed to replace persistent team chat tools, since by design it retains no message history and offers no built-in user directory, workspace, or admin management features.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dd982ac6-15fa-4c92-86fd-7b3367a55768';

